#include <bits/stdc++.h>
using namespace std;

int N;
long long S;
int a[25];
long long cnt = 0;

void dfs(int idx, int chosen, long long sum) {
    if (idx == N) {
        if (chosen > 0 && sum == S) cnt++;
        return;
    }
    dfs(idx + 1, chosen, sum);
    dfs(idx + 1, chosen + 1, sum + a[idx]);
}

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    cin >> N >> S;
    for (int i = 0; i < N; i++) cin >> a[i];
    dfs(0, 0, 0);
    cout << cnt << '\n';
    return 0;
}
